local LBuildingNpc = LxClass("LBuildingNpc", nil)
local typeSpineClick = typeof(CS.SpineClick)


-----------------------------------------------------------------
local typeofYXI2DObjectMover = typeof(CardEHT.YXI2DObjectMover)
local LBubbleStick = LxRequire("LApp.gameplay.Common.LBubbleStick")
local LGiftBubble = LXImport(".LGiftBubble")
local LTimeBubble = LXImport(".LTimeBubble")
