function LBuildingNpc:LBuildingNpc()
    self._displaySpine = nil
	self._clickFun = nil
	self._npcKey = nil
	self._talkData = nil
	self._npcTrans = nil
	
	self._displaySpineList = nil
	
	self._mainBody = nil
	self._subBodyList = nil
	
	self._lineK = -0.04
	self._lineB = 0.6
	self._curLineZ = nil
	
	self._pathIndex = 0
	self._isMoving = false
	self._pathList = {}
	
	self._moveSpeed = 1
	
	self._giftChangeTimer = nil

	self._bInstantNpcObject = false
end

function LBuildingNpc:SetParentTrans(trans)
end

function LBuildingNpc:CreateNpc(trans, key, bodyData, clickFun, bInstantObject)
	if CS.IsNullObject(trans) then return end

	self._bInstantNpcObject = bInstantObject
	if bInstantObject then
		local newtrans = LxResUtil.NewObject(trans.gameObject)
		if newtrans then
			newtrans = newtrans.transform
			LxUnity.SetParentTrans(newtrans, trans.transform.parent)
			newtrans.localPosition = trans.transform.localPosition
		end
		if CS.IsNullObject(newtrans) then return end

		trans = newtrans
	end

	self._mainBody = bodyData.main
	self._subBodyList = bodyData.subList
	if not string.isempty(bodyData.main.showText)then
		self._talkText = bodyData.main.showText
	end
	self._npcTrans = trans
	self._clickFun = clickFun
	self._npcKey = key
	local dp = LDisplaySpine:New()
	self._displaySpine = dp

	local scale = nil
	if self._mainBody.isFixScale then
		scale = self._mainBody.bodyScale
	else
		scale = self:GetLineScale(trans.position.y, self._mainBody.bodyScale)
	end

	dp:CreateSpine(trans , self._mainBody.spine)
	dp:SetLoadedFunction(function() 
		dp:SetScale(scale)
		if self._mainBody and self._mainBody.pos then
			local spineTrans = dp:GetDisplayTrans()
			spineTrans.localPosition = self._mainBody.pos
		end
		self:ShowTalk(self._talkText,self._talkData, self._talkOffset, self._talkPrefab)
		self:ShowGiftUI(self._bShowGiftUI)
		self:ShowTimeUI(self._bShowTimeUI)
		
		if self._mainBody and self._mainBody.initAni then
			self:PlayAni(self._mainBody.initAni, true)
		end

		local tran = dp:GetDisplayTrans()
		self:SetSpineClick(tran,self._mainBody.spineClick)
		local loadedFunc = self._mainBody.loadedFunc
		if loadedFunc ~= nil then
			loadedFunc()
		end
	end)
	dp:StartLoad()
	
	-- sub body
	if self._subBodyList then
		self._displaySpineList = {}
		for idx,subBody in ipairs(self._subBodyList) do
			local subDp = LDisplaySpine:New()
			table.insert(self._displaySpineList, subDp)
			subDp:CreateSpine(trans , subBody.spine)
			subDp:SetLoadedFunction(function() 
				subDp:SetScale(scale)
				if subBody.pos then
					local spineTrans = subDp:GetDisplayTrans()
					spineTrans.localPosition = subBody.pos
				end
			end)
			subDp:StartLoad()
		end
	end
end

function LBuildingNpc:Destroy()
	self:_StopMove()
	
	if self._displaySpineList then
		for idx,subDp in ipairs(self._displaySpineList) do
			subDp:Destroy()
		end
		self._displaySpineList = nil
	end
	
	if self._displaySpine then
		self._displaySpine:Destroy()
		self._displaySpine = nil
	end
	
	if self._bubbleStick then
		self._bubbleStick:DestroyBubble()
		self._bubbleStick = nil
	end
	
	if self._bubbleGift then
		self._bubbleGift:DestroyBubble()
		self._bubbleGift = nil
	end

	if self._bubbleTime then
		self._bubbleTime:DestroyBubble()
		self._bubbleTime = nil
	end
	
	if self._giftChangeTimer then
		LxTimer.DelayTimeStop(self._giftChangeTimer)
		self._giftChangeTimer = nil
	end
	if self._bInstantNpcObject and self._npcTrans then
		LxResUtil.DestroyObject(self._npcTrans.gameObject)
		self._npcTrans = nil
	end

	self._isDestroy = true
end

function LBuildingNpc:UpdateScale()
	if not self._displaySpine:IsDpValid() then return end
	
	local curPosZ = self._npcTrans.position.y
	if self._curLineZ and Mathf.Approximately(self._curLineZ, curPosZ) then return end

	local lineScale = self:GetLineScale(curPosZ, 1)
	self._scaleSize = lineScale
	self._curLineZ = curPosZ
	
	self._displaySpine:SetScale(lineScale * self._mainBody.bodyScale)
	if self._displaySpineList then
		for idx,subDp in ipairs(self._displaySpineList) do
			local bodyScale = 1
			local subBody = self._subBodyList[idx]
			if subBody then
				bodyScale = subBody.bodyScale
			end
			subDp:SetScale(lineScale * bodyScale)
		end
	end
end

function LBuildingNpc:GetLineScale(posy, baseScale)
	baseScale = baseScale or 1
	local lineK = self._lineK
	local lineB = self._lineB 
	local scale = lineK * posy + lineB
	if scale < 0 then
		scale = 0
	end
	return scale * baseScale
end

function LBuildingNpc:ShowTalk(text, talkData, offsetPos, prefabName)
	self._talkText = text
	self._talkData = talkData
	self._talkPrefab = prefabName
	self._talkOffset = offsetPos
	if string.isempty(text) then
		if self._bubbleStick then
			self._bubbleStick:DestroyBubble()
			self._bubbleStick = nil
		end
		return 
	end

	local bubbleStick = self._bubbleStick
	if not bubbleStick then
		self:CreateBubbleStick(offsetPos, self._talkPrefab)
		bubbleStick = self._bubbleStick
	end

	if not bubbleStick then return end

	bubbleStick:SetContent(text,0)
	bubbleStick:SetVisible(true)
	bubbleStick:SetPara({isWithin = false})
end

function LBuildingNpc:ShowGiftUI(bShow, offsetPos)
	self._bShowGiftUI = bShow
	local giftData = self._bodyGiftData
	if not bShow or not giftData then
		if self._bubbleGift then
			self._bubbleGift:DestroyBubble()
			self._bubbleGift = nil
		end
		return
	end

	local bubbleGift = self._bubbleGift
	if not bubbleGift then
		bubbleGift = self:CreateBubbleGift(offsetPos)
	end

	if not bubbleGift then return end

	local time = GetTimestamp()
	local timespan = giftData.endTime/1000 - time
	if timespan < 0 then
		timespan = 0
	end
	
	local ref = giftData.ref
	local showGiftName = giftData.showGiftName or false and true
	bubbleGift:SetTitleBgVisible(showGiftName)
	if showGiftName then
		local giftName = ccLngText(ref.giftName)
		bubbleGift:SetTitle(giftName)
	end

	local isSetTimeCn = giftData.setTimeCn
	if not isSetTimeCn then
		bubbleGift:SetTime(timespan)
	else
		bubbleGift:SetTimeCn(timespan)
	end

	bubbleGift:SetVisible(true)
end

function LBuildingNpc:ShowTimeUI(bShow, offsetPos)
	self._bShowTimeUI = bShow
	local timeData = self._bodyTimeData
	if not bShow or not timeData then
		if self._bubbleTime then
			self._bubbleTime:DestroyBubble()
			self._bubbleTime = nil
		end
		return
	end

	local bubbleTime = self._bubbleTime
	if not bubbleTime then
		bubbleTime = self:CreateBubbleTime(offsetPos)
	end

	if not bubbleTime then return end

	local time = GetTimestamp()
	local timespan = timeData.endTime/1000 - time
	if timespan < 0 then
		timespan = 0
	end
	local isSetTimeCn = timeData.setTimeCn
	if not isSetTimeCn then
		bubbleTime:SetTime(timespan)
	else
		bubbleTime:SetTimeCn(timespan)
	end
	bubbleTime:SetVisible(true)
end

function LBuildingNpc:CreateBubbleStick(offsetPos, prefabName)
	if not self._displaySpine:IsDpValid() then return end

	local bubbleStick = LBubbleStick:New()
	local dpTarns = self._displaySpine:GetDisplayTrans()
	offsetPos = offsetPos or Vector3.New(0,0.7,0)
	bubbleStick:CreateBubble(prefabName)
	bubbleStick:SetHeroTrans(dpTarns, offsetPos)
	bubbleStick:AddClickFunc(function()
		if self._clickFun then
			self._clickFun(self)
		end
	end, true)
	self._bubbleStick = bubbleStick
	return bubbleStick
end

function LBuildingNpc:CreateBubbleGift(offsetPos)
	if not self._displaySpine:IsDpValid() then return end

	local bubbleGift = LGiftBubble:New()
	local dpTarns = self._displaySpine:GetDisplayTrans()
	offsetPos = offsetPos or Vector3.New(0,0.3,0)
	bubbleGift:CreateBubble()
	bubbleGift:SetHeroTrans(dpTarns, offsetPos)
	bubbleGift:AddClickFunc(function()
		if self._clickFun then
			self._clickFun(self)
		end
	end, true)
	self._bubbleGift = bubbleGift
	return bubbleGift
end

function LBuildingNpc:CreateBubbleTime(offsetPos)
	if not self._displaySpine:IsDpValid() then return end

	local bubbleTime = LTimeBubble:New()
	local dpTrans = self._displaySpine:GetDisplayTrans()
	offsetPos = offsetPos or Vector3.New(0,-0.3, 0)
	bubbleTime:CreateBubble()
	bubbleTime:SetHeroTrans(dpTrans, offsetPos)
	bubbleTime:AddClickFunc(function()
		if self._clickFun then
			self._clickFun(self)
		end
	end, true)
