function LBuildingNpc:SetDirectionByPos(tarPos)
	local dir = 1
	local nowPos = self:GetPosition()
	if nowPos.x > tarPos.x then
		dir =  1
	elseif nowPos.x < tarPos.x then
		dir =  2
	end	
	self:SetDirection(dir)
end

function LBuildingNpc:GetChangeDir(nowPos, tarPos, defaultDir)
	if nowPos.x > tarPos.x then
		return 1
	elseif nowPos.x < tarPos.x then
		return 2
	end
	return defaultDir
end

function LBuildingNpc:SetDirection(dir)
	if not self._displaySpine:IsDpValid() then return false end 

	self._direction = dir
	local baseDir = 1
	if self._mainBody then
		baseDir = self._mainBody.dir or 1
	end
	self._displaySpine:SetFlipX(dir ~= baseDir)
	if self._displaySpineList then
		for idx,subDp in ipairs(self._displaySpineList) do
			local subBody = self._subBodyList[idx]
			if subBody then
				subDp:SetFlipX(dir ~= subBody.dir)
			end
		end
	end
end

function LBuildingNpc:GetDirection()
	return self._direction
end 
