-- spine ani
function LBuildingNpc:IsIdleAni()
	return self:IsAni("idle") 
end

function LBuildingNpc:IsRunAni()
	return self:IsAni("run") 
end

function LBuildingNpc:PlayIdleAni()
	self:PlayAni("idle", true)
	if self._displaySpine:IsDpValid() then 
		self._displaySpine:SetAnimationTimeScale(1)
		
		if self._displaySpineList then
			for idx,subDp in ipairs(self._displaySpineList) do
				subDp:SetAnimationTimeScale(1)
			end
		end
	end 
end

function LBuildingNpc:PlayRunAni()
	self:PlayAni("run", true)
	if self._displaySpine:IsDpValid() then 
		self._displaySpine:SetAnimationTimeScale(self._moveSpeed * self._mainBody.aniScale)
		
		if self._displaySpineList then
			for idx,subDp in ipairs(self._displaySpineList) do
				local subBody = self._subBodyList[idx]
				if subBody then
					subDp:SetAnimationTimeScale(self._moveSpeed * subBody.aniScale)
				end 
			end
		end
	end 
end

function LBuildingNpc:IsAni(ani)
	if not self._displaySpine:IsDpValid() then return false end 

	return self._displaySpine:GetCurAnimationName() == ani
end

function LBuildingNpc:PlayAni(animationName,bLoop,mixTime)
	if not self._displaySpine:IsDpValid() then return end 

	self._displaySpine:PlayAnimation(0,animationName,bLoop,false,mixTime)
	if self._displaySpineList then
		for idx,subDp in ipairs(self._displaySpineList) do
			subDp:PlayAnimation(0,animationName,bLoop,false,mixTime)
		end
	end
end
