---挂移动组件
function LBuildingNpc:InitMoveCom()
	if CS.IsNullObject(self._npcTrans) then return end
	
	local dpGo = self._npcTrans.gameObject
	local comp = dpGo:GetComponent(typeofYXI2DObjectMover)
	if not comp then
		comp = dpGo:AddComponent(typeofYXI2DObjectMover)
	end

	self._ObjMover = comp
	self._isCanMove = true
end

function LBuildingNpc:CreateMovePath(pathRoot, bornIndex)
	if CS.IsNullObject(pathRoot) then return end
	
	local pointCount = pathRoot.childCount
	if pointCount == 0 then return end
	
	self:InitMoveCom()	
	self._pointList = {}
	for iPoint = 1, pointCount do
		local pointTrans = pathRoot:Find(tostring(iPoint))
		if pointTrans then
			local pointItem = {}
			pointItem.trans = pointTrans
			pointItem.isBorn = (bornIndex == iPoint)
			pointItem.position = pointTrans.localPosition
			pointItem.index = iPoint
			table.insert(self._pointList, pointItem)
			if pointItem.isBorn then
				self:SetPos(pointItem.position)
			end
		end
	end
end

function LBuildingNpc:MoveToIndex(idx, endFunc)
	if not self._isCanMove then
		if endFunc then
			endFunc(self)
		end
		return
	end
	
	self._moveEndFunc = endFunc	
	self._pathIndex = 0
	
	local fromIndex = self._curPointIndex or 1
	local toIndex = idx
	local maxIndex = #self._pointList
	fromIndex = Mathf.Clamp(fromIndex, 1, maxIndex)
	toIndex = Mathf.Clamp(toIndex, 1, maxIndex)
	
	self._targetPointIndex = toIndex
	
	local objMover = self._ObjMover
	self._pathList = {}
	for i = fromIndex,toIndex do
		local pointItem = self._pointList[i]
		local pos = pointItem.position
		if 0 == #self._pathList then
			objMover:AddPathPoint(pos, true)
		else
			objMover:AddPathPoint(pos, false)
		end
		table.insert(self._pathList, pointItem)
	end
	
	if #self._pathList > 0 then
		objMover:StartPathMove(self._moveSpeed)
		if not self:IsRunAni() then
			self._ObjMover:SetSpeed(self._moveSpeed)
			self:PlayRunAni()
		end
		
		self:_StartMove()
	else
		self:_StopMove()
	end
end

function LBuildingNpc:MoveToEnd(endFunc)
	if not self._pointList then
		if endFunc then
			endFunc(self)
		end
		return
	end
	local idx = #self._pointList
	self:MoveToIndex(idx, endFunc)
end

function LBuildingNpc:OnMoveEnd()
	self._curPointIndex = self._targetPointIndex 
	
	self:_StopMove()
	
	if self._moveEndFunc then
		self._moveEndFunc()
	end
end

function LBuildingNpc:_StartMove()
	if self._runTimer then
		self:_StopMove()
	end
	self._isMoving = true
	self._runTimer = LxTimer.LoopTimeCall(function () self:_OnMoveRun() end, 0, false) 
end

function LBuildingNpc:_StopMove()
	if self._runTimer then
		LxTimer.LoopTimeStop(self._runTimer)
		self._runTimer = nil
	end
end

function LBuildingNpc:_OnMoveRun(deltaTime)
	local objMover = self._ObjMover
	if CS.IsNullObject(objMover) then
		self._isMoving = false
		return 
	end
	
	local isMoving = self._ObjMover:IsMoving()
	if isMoving then
		self:UpdateScale()
		local currentIndex = self._ObjMover:GetCurrentIndex()
		if currentIndex ~= self._pathIndex then
			self._pathIndex = currentIndex
			if currentIndex < #self._pathList then
				local fromItem = self._pathList[currentIndex]
				local toItem = self._pathList[currentIndex+1]
				local startPos = fromItem.position
				local endPos = toItem.position
				
				self._curPointIndex = fromItem.index
				
				local dir = self:GetChangeDir(startPos, endPos, self:GetDirection())
				self:SetDirection(dir)
				
				if not self:IsRunAni() then
					self:PlayRunAni()
					self._ObjMover:SetSpeed(self._moveSpeed)
				end 
			elseif not self:IsRunAni() then
				self:PlayRunAni()
				self._ObjMover:SetSpeed(self._moveSpeed)
			end 
		end	
	else
		if self:IsRunAni() then
			self:PlayIdleAni() 
			self:OnMoveEnd()
		end 
	end

	self._isMoving = isMoving
end

function LBuildingNpc:IsMoving()
	return self._isMoving
end

function LBuildingNpc:SetGiftBubbleVisible(isVisible)
	if self._bubbleGift then
		self._bubbleGift:SetVisible(isVisible)
	end
end

function LBuildingNpc:SetSpineClick(tran,func)
	if not CS.IsValidObject(tran) then return end

	local comp = tran.transform:GetComponent(typeSpineClick)
	if not comp then
		comp = tran.gameObject:AddComponent(typeSpineClick)
	end
	comp.onClick = func
end

return LBuildingNpc